const body = $input.first().json.body;

const fields = body?.data?.fields || [];

let fullName = '';
let email = '';
let fileUrl = '';

for (const field of fields) {
  const label = (field.label || '').toLowerCase();
  const value = field.value;

  if (label.includes('name')) {
    fullName = value || '';
  }
  if (label.includes('email')) {
    email = value || '';
  }
  if (label.includes('resume') || label.includes('file') || label.includes('upload')) {
    if (Array.isArray(value) && value.length > 0) {
      fileUrl = value[0].url || '';
    }
  }
}

if (!email) throw new Error('Email nahi mili form se');
if (!fileUrl) throw new Error('PDF URL nahi mila form se');

return [{
  json: {
    fullName: fullName || 'Candidate',
    email,
    fileUrl
  }
}];

const pdfData = $input.first().json;
const prev = $('Extract Form Data').first().json;

const resumeText = pdfData.text || pdfData.content || '';

if (!resumeText.trim()) {
  throw new Error('PDF se text nahi mila - searchable PDF use karo');
}

const prompt = 'Analyze this resume and return JSON only:\n\nRESUME:\n' + resumeText.slice(0, 3000) + '\n\nReturn exactly:\n{"candidate_name": "full name","current_role": "job title","experience": "X+ years","top_skills": ["skill1","skill2","skill3"],"score": 85,"strengths": ["s1","s2","s3"],"improvements": ["i1","i2"],"summary": "2-3 sentence assessment"}';

return [{
  json: {
    resumeText: resumeText.slice(0, 3000),
    email: prev.email,
    fullName: prev.fullName,
    groqBody: {
      model: 'llama-3.3-70b-versatile',
      temperature: 0.3,
      max_tokens: 1000,
      response_format: { type: 'json_object' },
      messages: [
        {
          role: 'system',
          content: 'You are an HR expert. Reply with valid JSON only. No markdown. No extra text.'
        },
        {
          role: 'user',
          content: prompt
        }
      ]
    }
  }
}];

const response = $input.first().json;
const prev = $('Extract Form Data').first().json;

const analysis = typeof response.choices[0].message.content === 'string'
  ? JSON.parse(response.choices[0].message.content)
  : response.choices[0].message.content;

const score = analysis.score || 0;
const scoreLabel = score >= 75 ? '🟢 Strong Profile' : score >= 50 ? '🟡 Good Profile' : '🔴 Needs Improvement';

return [{
  json: {
    candidate_name: analysis.candidate_name || prev.fullName,
    current_role: analysis.current_role || 'Not mentioned',
    experience: analysis.experience || 'Not mentioned',
    top_skills: analysis.top_skills || [],
    score: score,
    score_label: scoreLabel,
    strengths: analysis.strengths || [],
    improvements: analysis.improvements || [],
    summary: analysis.summary || '',
    email: prev.email,
    fullName: prev.fullName
  }
}];
